using System; class Program { static double ToRadians(double a) => Math.PI * a / 180.0; static void Main() { double latM=48.725278; double lonM=2.359444; double lat1=latM * Math.PI / 180.0; double lon1=lonM * Math.PI / 180.0; var r=3440.065; var dLat=ToRadians(latM-lat1); var dLon=ToRadians(lonM-lon1); var a=Math.Sin(dLat/2)*Math.Sin(dLat/2)+Math.Cos(ToRadians(lat1))*Math.Cos(ToRadians(latM))*Math.Sin(dLon/2)*Math.Sin(dLon/2); var c=2*Math.Atan2(Math.Sqrt(a), Math.Sqrt(1-a)); Console.WriteLine("Dist: " + (r*c)); } }
